if (! function_exists('text_syllable_counter')) {
    function text_syllable_counter($text, $per_word = null)
    {
        $words = preg_split('/\s+/', trim($text));
        $words = array_filter($words, function($w) { return preg_match('/[a-zA-Z]/', $w); });
        $words = array_values($words);

        if (empty($words)) {
            return json_encode(['error' => 'No words found in text', 'total_syllables' => 0]);
        }

        function countSyllables($word) {
            $word = strtolower(trim($word));
            $word = preg_replace('/[^a-z]/', '', $word);
            if (strlen($word) === 0) return 0;
            if (strlen($word) <= 2) return 1;
            
            // Exception dictionary for words the heuristic gets wrong
            $exceptions = [
                'carrying' => 3, 'memories' => 3, 'every' => 3, 'evening' => 3,
                'area' => 3, 'idea' => 3, 'cafe' => 2, 'being' => 2, 'doing' => 2,
                'going' => 2, 'seeing' => 2, 'poem' => 2, 'poet' => 2, 'quiet' => 2,
                'lion' => 2, 'fuel' => 2, 'cruel' => 2, 'fire' => 2, 'hire' => 2,
                'flower' => 2, 'power' => 2, 'layer' => 2, 'player' => 2, 'prayer' => 2,
                'higher' => 2, 'science' => 2, 'diamond' => 3, 'violet' => 3,
                'actual' => 3, 'annual' => 3, 'visual' => 3, 'manual' => 3,
                'genuine' => 3, 'recipe' => 3, 'heaven' => 2, 'seven' => 2,
                'even' => 2, 'children' => 2,
            ];
            
            if (isset($exceptions[$word])) {
                return $exceptions[$word];
            }
            
            // Count vowel groups
            $count = 0;
            $prevVowel = false;
            $vowels = 'aeiouy';
            
            for ($i = 0; $i < strlen($word); $i++) {
                $isVowel = strpos($vowels, $word[$i]) !== false;
                if ($isVowel && !$prevVowel) {
                    $count++;
                }
                $prevVowel = $isVowel;
            }
            
            // Adjust for silent e at end
            if (substr($word, -1) === 'e' && $count > 1) {
                if (strlen($word) > 2 && !in_array(substr($word, -2), ['le', 'ce', 'ge'])) {
                    $secondLast = substr($word, -2, 1);
                    if (!in_array($secondLast, ['e', 'o', 'y', 'u'])) {
                        $count--;
                    }
                }
            }
            // Adjust for "es" and "ed" endings
            if (substr($word, -2) === 'es' && $count > 1) {
                if (strlen($word) > 3) {
                    $count--;
                }
            }
            if (substr($word, -2) === 'ed' && $count > 1 && !in_array(substr($word, -3, 1), ['d', 't'])) {
                $count--;
            }
            
            return max(1, $count);
        }

        if ($per_word) {
            $wordCounts = [];
            foreach ($words as $w) {
                $clean = preg_replace('/[^a-zA-Z]/', '', $w);
                $wordCounts[] = [
                    'word' => $w,
                    'syllables' => countSyllables($clean)
                ];
            }
            $total = array_sum(array_column($wordCounts, 'syllables'));
            return json_encode([
                'total_syllables' => $total,
                'word_count' => count($words),
                'per_word' => $wordCounts
            ]);
        }

        $total = 0;
        foreach ($words as $w) {
            $clean = preg_replace('/[^a-zA-Z]/', '', $w);
            $total += countSyllables($clean);
        }
        return json_encode([
            'text' => $text,
            'total_syllables' => $total,
            'word_count' => count($words),
            'avg_syllables_per_word' => count($words) > 0 ? round($total / count($words), 2) : 0
        ]);
    }
}
